mapper.select:
SELECT rep.*, b.name AS buildingName, u.name AS unitName, -- 补充单元名称 r.room_num AS roomNum, o.name AS ownerName, o.phone AS ownerPhone FROM bus_repair rep LEFT JOIN bus_room r ON rep.room_id = r.id LEFT JOIN bus_unit u ON r.unit_id = u.id -- 关联单元表 LEFT JOIN bus_building b ON r.building_id = b.id LEFT JOIN bus_owner o ON rep.owner_id = o.id
rep.is_deleted = 0
AND rep.owner_id = #{query.ownerId}
AND rep.handler_id = #{query.handlerId}
AND rep.status = #{query.status}
AND r.room_num LIKE CONCAT('%', #{query.roomNum}, '%')
ORDER BY rep.create_time DESC
